int process_packet(struct sk_buff *skb)
{
	struct ethhdr *eth;
	struct iphdr *iph;
	struct udphdr *udph;
	unsigned int proto;
	unsigned int len;
	int src_port;
	int dst_port;
	int err;

	eth = eth_hdr(skb);
	iph = ip_hdr(skb);
	udph = udp_hdr(skb);
	proto = iph->protocol;
	len = ntohs(iph->tot_len);
	src_port = ntohs(udph->source);
	dst_port = ntohs(udph->dest);
	err = route_packet(skb, src_port, dst_port);
	return err;
}
